mapper.select:
SELECT id, batch_no, table_name, data_id, data_version, operate_type, data_from, data_to, create_time, create_by FROM mdm_change_log WHERE deleted = 0 AND create_time >= #{timeFrom} AND create_time <= #{timeTo} AND batch_no = #{batchNo} AND table_name = #{tableName} AND data_id = #{dataId} AND operate_type = #{operateType} AND create_by = #{createBy}
AND ( data_from LIKE CONCAT('%', #{keyword}, '%') OR data_to LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY id DESC
